import {
    Accordion,
    AccordionActions,
    AccordionDetails,
    AccordionSummary,
    Button,
    Checkbox,
    Dialog,
    DialogActions,
    DialogContent,
    DialogContentText,
    DialogTitle,
    FormControlLabel,
    Grid,
    makeStyles,
    useMediaQuery
} from "@material-ui/core";
import ExpandMoreIcon from '@material-ui/icons/ExpandMore';
import {useState} from "react";
import moment from "moment";
import EditDialog from "../edit-dialog/EditDialog";
import ReactMarkdown from 'react-markdown';

const useStyles = makeStyles((theme) => ({
    root: {
        width: '100%',
    },
    heading: {
        fontSize: theme.typography.pxToRem(15),
    },
    secondaryHeading: {
        fontSize: theme.typography.pxToRem(15),
        color: theme.palette.text.secondary,
        verticalAlign: 'middle'
    },
    column: {
        flexBasis: '40%',
    },
    fat: {
        fontWeight: 600
    }
}));

const compareAlphabetically = (a, b) => {
    return a.title.toLowerCase() > b.title.toLowerCase();
};

function sort(sortMethod, todos) {
    switch (sortMethod) {
        case 'default': {
            return todos.sort(compareAlphabetically);
        }
        case 'oldest-first': {
            return todos.filter(todo => todo.dueDate).sort((a, b) => {
                return a.dueDate > b.dueDate;
            });
        }
        case 'by-title': {
            return todos.filter(todo => !todo.dueDate).sort(compareAlphabetically);
        }
    }
}

export default function TodoList({todos, setTodos, sortMethod, query}) {

    const [deleteOpen, setDeleteOpen] = useState(false);
    const [editOpen, setEditOpen] = useState(false);
    const [dialogTodo, setDialogTodo] = useState({});
    const isDesktop = useMediaQuery('(min-width: 600px)');
    const classes = useStyles();

    const handleChange = (event, id) => {
        const newTodo = todos.find(todo => todo._id === id);
        fetch(`http://localhost:8080/todo/${id}`, {
            method: 'PUT',
            credentials: 'include',
            body: JSON.stringify({
                title: newTodo.title,
                done: !newTodo.done,
                dueDate: newTodo.dueDate,
                information: newTodo.information
            }),
            headers: {
                'Content-Type': 'application/json'
            }
        }).then(res => res.json()).then(updateTodo => {
            const newTodos = todos.map(todo => todo._id === id ? updateTodo : todo);
            setTodos(newTodos);
        }).catch(console.log);
    };

    const showDeleteDialog = (event, id) => {
        setDialogTodo(todos.find(todo => todo._id === id));
        setDeleteOpen(true);
    };

    const showEditDialog = (event, id) => {
        setDialogTodo(todos.find(todo => todo._id === id));
        setEditOpen(true);
    }

    const deleteTodo = (event, id) => {
        fetch(`${process.env.REACT_APP_BACKEND_URL}/todo/${id}`, {
            method: 'DELETE',
            credentials: 'include'
        }).then(() => {
            const newTodos = todos.filter(todo => todo._id !== id);
            setTodos(newTodos);
        }).catch(console.log);
    };

    const matchesQuery = todo => {
        return todo.description?.toLowerCase().includes(query.toLowerCase().trim()) ||
            todo.title.toLowerCase().includes(query.toLowerCase().trim());
    }

    const saveEditedTodo = () => {
        fetch(`${process.env.REACT_APP_BACKEND_URL}/todo/${dialogTodo._id}`, {
            method: 'PUT',
            credentials: 'include',
            body: JSON.stringify({
                title: dialogTodo.title,
                done: dialogTodo.done,
                dueDate: dialogTodo.dueDate,
                information: dialogTodo.information
            }),
            headers: {
                'Content-Type': 'application/json'
            }
        }).then(res => res.json()).then(updateTodo => {
            const newTodos = todos.map(todo => todo._id === dialogTodo._id ? updateTodo : todo);
            setTodos(newTodos);
        }).catch(console.log);
    };

    let renderTodos = sort(sortMethod, todos);

    if (query.trim() !== '') {
        renderTodos = renderTodos.filter(todo => matchesQuery(todo));
    }

    const accordions = renderTodos.map(todo => {
        return <Accordion key={todo._id}>
            <AccordionSummary
                expandIcon={!isDesktop && <ExpandMoreIcon/>}
                aria-label="Expand"
                aria-controls="additional-actions1-content"
                id="additional-actions1-header">
                <FormControlLabel
                    onClick={(event) => event.stopPropagation()}
                    onFocus={(event) => event.stopPropagation()}
                    checked={todo.done === true || todo.done === 'true'}
                    onChange={(event) => handleChange(event, todo._id)}
                    control={<Checkbox/>}
                    label={todo.title}>
                </FormControlLabel>
            </AccordionSummary>
            <AccordionDetails>
                <Grid container spacing={3}>
                    {todo.dueDate &&
                    <Grid className={classes.fat} item xs={12}>{moment(todo.dueDate).calendar()}</Grid>}
                    {todo.information && <Grid item xs={12}><ReactMarkdown children={todo.information}/></Grid>}
                </Grid>
            </AccordionDetails>
            <AccordionActions>
                <Button onClick={(event) => showEditDialog(event, todo._id)} variant="contained"
                        color="primary">Edit</Button>
                <Button onClick={(event) => showDeleteDialog(event, todo._id)}
                        variant="contained"
                        color="secondary">Delete</Button>
            </AccordionActions>
        </Accordion>
    });

    const handleClose = () => {
        setDeleteOpen(false);
    }

    const deleteDialog = (<Dialog open={deleteOpen}
                                  onClose={handleClose}
                                  aria-labelledby="alert-dialog-title"
                                  aria-describedby="alert-dialog-description">
        <DialogTitle id="alert-dialog-title">{"Confirm deletion"}</DialogTitle>
        <DialogContent>
            <DialogContentText id="alert-dialog-description">
                Are you sure you want to delete '{dialogTodo.title}'
            </DialogContentText>
        </DialogContent>
        <DialogActions>
            <Button onClick={handleClose} color="primary">
                Abort
            </Button>
            <Button onClick={(event) => {
                handleClose();
                deleteTodo(event, dialogTodo._id);
            }} color="secondary" autoFocus>
                Delete
            </Button>
        </DialogActions>
    </Dialog>);

    return (<>
        {accordions}
        {deleteDialog}
        <EditDialog save={saveEditedTodo} todo={dialogTodo} setTodo={setDialogTodo} open={editOpen}
                    setOpen={setEditOpen}/>
    </>);
}
